const input = $input.first().json;
const headers = Object.fromEntries(Object.entries(input.headers ?? {}).map(([key, value]) => [key.toLowerCase(), value]));
const body = input.body ?? {};
const expectedSecret = process.env.N8N_SHARED_SECRET ?? 'CHANGE_ME';
const actualSecret = headers['x-n8n-shared-secret'];

if (!actualSecret) {
  throw new Error('Missing X-N8N-Shared-Secret header');
}

if (expectedSecret === 'CHANGE_ME') {
  throw new Error('Set N8N_SHARED_SECRET before publishing this workflow');
}

if (actualSecret !== expectedSecret) {
  throw new Error('Invalid shared secret');
}

const requiredFields = ['request_id', 'dedup_key', 'name', 'email', 'phone', 'title', 'body'];
for (const field of requiredFields) {
  if (!body[field]) {
    throw new Error(`Missing required field: ${field}`);
  }
}

return [{
  json: {
    workflow: 'inquiry_register',
    request_id: body.request_id,
    dedup_key: body.dedup_key,
    name: body.name,
    email: body.email,
    phone: body.phone,
    title: body.title,
    inquiry_body: body.body,
    admin_email: body.admin_email ?? '',
    notion_database_id: body.notion_database_id ?? '',
    received_at: new Date().toISOString()
  }
}];
